-- Full Arabic texts for the Kitab Pesantren library, parsed from the
-- OpenITI corpus (public-domain Shamela digitisations; per-book source URIs
-- in the comments below). Structure verified per book before parsing.
-- translation_id is NULL throughout: terjemah must come from a verified
-- source, never machine-filled here (the reader shows Arabic; narration
-- works in Arabic). New bab_order starts at 100 to never collide with the
-- existing hand-curated bab rows.

-- Matan Taqrib (al-Ghaya wa-t-Taqrib, Abu Syuja' al-Isfahani) is NEW to the
-- library — the foundational Shafi'i matn that Fathul Qarib comments on.
INSERT OR IGNORE INTO pesantren_kitab (slug, category_slug, title_ar, title_id, author, author_death_year, description_id, sort_order)
SELECT 'taqrib', category_slug, 'متن الغاية والتقريب', 'Matan Taqrib (Abu Syuja'')', 'Abu Syuja'' Ahmad al-Isfahani', '593 H',
  'Matan fiqih Syafi''i paling mendasar di pesantren — ringkas, padat, menjadi induk yang disyarahi Fathul Qarib.', 90
FROM pesantren_kitab WHERE slug = 'fathulqarib';



-- ═══ jurumiyah — OpenITI 0723IbnAjrum.Ajrumiyya.Shamela0011371-ara1 ═══
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 100, 'مدخل', 'مدخل');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, '...

بسم الله الرحمن الرحيم

أنواع الكلام

الكلام: هو اللفظ المركب المفيد بالوضع. وأقسامه ثلاثة: اسم، وفعل، وحرف جاء لمعنى.

فالاسم يعرف: بالخفض، والتنوين، ودخول الألف واللام، وحروف الخفض, وهي: من، وإلى، وعن، وعلى، وفي, ورب، والباء، والكاف، واللام، وحروف القسم وهي: الواو، والباء، والتاء.

والفعل يعرف بقد، والسين، وسوف، وتاء التأنيث الساكنة.

والحرف ما لا يصلح معه دليل الاسم ولا دليل الفعل.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 100;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 101, 'باب الإعراب', 'باب الإعراب');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'الإعراب هو تغيير أواخر الكلم، لاختلاف العوامل الداخلة عليها لفظا أو تقديرا.

وأقسامه أربعة: رفع، ونصب، وخفض، وجزم. فللأسماء من ذلك الرفع، والنصب، والخفض، ولا جزم فيها, وللأفعال من ذلك: الرفع، والنصب، والجزم, ولا خفض فيها.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 101;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 102, 'باب معرفة علامات الإعراب', 'باب معرفة علامات الإعراب');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'للرفع أربع علامات: الضمة، والواو، والألف، والنون.

فأما الضمة فتكون علامة للرفع في أربعة مواضع في الاسم المفرد، وجمع التكسير، وجمع المؤنث السالم، والفعل المضارع الذي لم يتصل بآخره شيء.

وأما الواو فتكون علامة للرفع في موضعين: في جمع المذكر السالم وفي الأسماء الخمسة، وهي: أبوك وأخوك وحموك وفوك وذو مال.

وأما الألف فتكون علامة للرفع في تثنية الأسماء خاصة.

وأما النون فتكون علامة للرفع في الفعل المضارع, إذا اتصل به ضمير تثنية، أو ضمير جمع، أو ضمير المؤنثة المخاطبة.

وللنصب خمس علامات: الفتحة, والألف، والكسرة، والياء، وحذف النون.

فأما الفتحة فتكون علامة للنصب في ثلاثة مواضع: في الاسم المفرد, وجمع التكسير، والفعل المضارع إذا دخل عليه ناصب ولم يتصل بآخره شيء.

وأما الألف: فتكون علامة للنصب في الأسماء الخمسة نحو: "رأيت أباك وأخاك" وما أشبه ذلك.

وأما الكسرة: فتكون علامة للنصب في جمع المؤنث السالم.

وأما الياء: فتكون علامة للنصب في التثنية والجمع.

وأما حذف النون فيكون علامة للنصب في الأفعال الخمسة التي رفعها بثبات النون.

الكسرة، والياء، والفتحة.

وللخفض ثلاث علامات:

فأما الكسرة: فتكون علامة للخفض في ثلاثة مواضع: في الاسم المفرد المنصرف، وجمع التكسير المنصرف، وفي جمع المؤنث السالم.

وأما الياء: فتكون علامة للخفض في ثلاثة مواضع: في الأسماء الخمسة، وفي التثنية, ms1 والجمع.

وأما الفتحة: فتكون علامة للخفض في الاسم الذي لا ينصرف.

وللجزم علامتان: السكون, والحذف.

فأما السكون فيكون علامة للجزم في الفعل المضارع الصحيح الآخر.

وأما الحذف فيكون علامة للجزم في الفعل المضارع المعتل الآخر، وفي الأفعال الخمسة التي رفعها بثبات النون.

فصل: المعربات

المعربات قسمان: قسم يعرب بالحركات، وقسم يعرب بالحروف.

فالذي يعرب بالحركات أربعة أنواع1: الاسم المفرد، وجمع التكسير، وجمع المؤنث السالم، والفعل المضارع الذي لم يتصل بآخره شيء.

وكلها ترفع بالضمة، وتنصب بالفتحة، وتخفض بالكسرة، وتجزم بالسكون.

وخرج عن ذلك ثلاثة أشياء: جمع المؤنث السالم ينصب بالكسرة، والاسم الذي لا ينصرف يخفض بالفتحة، والفعل المضارع المعتل الآخر يجزم بحذف آخره.

والذي يعرب بالحروف أربعة أنواع: التثنية، وجمع المذكر السالم، والأسماء الخمسة، والأفعال الخمسة، وهي: يفعلان، وتفعلان، ويفعلون، وتفعلون، وتفعلين.

فأما التثنية: فترفع بالألف، وتنصب وتخفض بالياء.

وأما جمع المذكر السالم: فيرفع بالواو، وينصب ويخفض بالياء.

وأما الأسماء الخمسة: فترفع بالواو، وتنصب بالألف، وتخفض بالياء.

وأما الأفعال الخمسة: فترفع بالنون وتنصب وتجزم بحذفها.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 102;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 103, 'باب الأفعال', 'باب الأفعال');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'الأفعال ثلاثة: ماض، ومضارع، وأمر، نحو: ضرب، ويضرب، واضرب. فالماضي: مفتوح الآخر أبدا. والأمر: مجزوم أبدا.

والمضارع: ما كان في أوله إحدى الزوائد الأربع التي يجمعها قولك: "أنيت" وهو مرفوع أبدا، حتى يدخل عليه ناصب أو جازم.

فالنواصب عشرة، وهي:

أن، ولن، وإذن، وكي، ولام كي، ولام الجحود، وحتى، والجواب بالفاء والواو, وأو.

والجوازم ثمانية عشر، وهي:

لم، لما، ألم، ألما، ولام الأمر والدعاء، و"لا" في النهي والدعاء، وان، وما، ومن، ومهما، واذما، وأي، ومتى، وأيان، وأين، وأنى، وحيثما، وكيفما، وإذا في الشعر خاصة.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 103;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 104, 'باب مرفوعات الأسماء', 'باب مرفوعات الأسماء');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'المرفوعات سبعة، وهي:

الفاعل، والمفعول الذي لم يسم فاعله، والمبتدأ وخبره، واسم كان وأخواتها، وخبر إن وأخواتها، والتابع للمرفوع، وهو أربعة أشياء: النعت، والعطف، والتوكيد، والبدل.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 104;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 105, 'باب الفاعل', 'باب الفاعل');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'الفاعل هو: الاسم المرفوع المذكور قبله فعله.

وهو على قسمين: ظاهر , ومضمر.

فالظاهر نحو قولك: قام زيد، ويقوم زيد، وقام الزيدان، ويقوم الزيدان، وقام الزيدون، ويقوم الزيدون، وقام ms2 الرجال، ويقوم الرجال، وقامت هند، وتقوم هند، وقامت الهندان، وتقوم الهندان، وقامت الهندات، وتقوم الهندات، وقامت الهنود، وتقوم الهنود، وقام أخوك، ويقوم أخوك، وقام غلامي، ويقوم غلامي، وما أشبه ذلك.

والمضمر اثنا عشر، نحو قولك: "ضربت، وضربنا، وضربت، وضربت، وضربتما، وضربتم، وضربتن، وضرب، وضربت، وضربا، وضربوا، وضربن".', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 105;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 106, 'باب المفعول الذي لم يسم فاعله', 'باب المفعول الذي لم يسم فاعله');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وهو الاسم المرفوع, الذي لم يذكر معه فاعله.

فإن كان الفعل ماضيا: ضم أوله وكسر ما قبل آخره، وان كان مضارعا: ضم أوله وفتح ما قبل آخره. وهو على قسمين: ظاهر، ومضمر؛ فالظاهر نحو قولك: "ضرب زيد" و"يضرب زيد" و"أكرم عمرو" و"يكرم عمرو". والمضمر اثنا عشر، نحو قولك: "ضربت، وضربنا، وضربت، وضربت، وضربتما، وضربتم، وضربتن، وضرب، وضربت، وضربا، وضربوا، وضربن".', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 107, 'باب المبتدأ والخبر', 'باب المبتدأ والخبر');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'المبتدأ: هو الاسم المرفوع العاري عن العوامل اللفظية.

والخبر: هو الاسم المرفوع المسند إليه، نحو قولك: "زيد قائم" و"الزيدان قائمان" و"الزيدون قائمون".

والمبتدأ قسمان: ظاهر ومضمر.

فالظاهر ما تقدم ذكره.

والمضمر اثنا عشر، وهي:

أنا، ونحن، وأنت، وأنت، وأنتما، وأنتم، وأنتن، وهو، وهي، وهما، وهم، وهن، نحو قولك: "أنا قائم" و"نحن قائمون" وما أشبه ذلك.

والخبر قسمان: مفرد؛ وغير مفرد.

فالمفرد نحو قولك: "زيد قائم".

وغير المفرد أربعة أشياء: الجار والمجرور، والظرف، والفعل مع فاعله، والمبتدأ مع خبره، نحو قولك: "زيد في الدار، وزيد عندك، وزيد قام أبوه، وزيد جاريته ذاهبة".', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 108, 'باب العوامل الداخلة على المبتدأ والخبر', 'باب العوامل الداخلة على المبتدأ والخبر');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وهي ثلاثة أشياء: كان وأخواتها، وان وأخواتها، وظننت وأخواتها.

فأما كان وأخواتها , فإنها ترفع الاسم, وتنصب الخبر، وهي: كان، وأمسى، وأصبح، وأضحى، وظل، وبات، وصار، وليس، وما زال، وما انفك، وما فتيء، وما برح، وما دام، وما تصرف منها نحو: كان, ويكون, وكن، وأصبح ويصبح, وأصبح، تقول: "كان زيد قائما، وليس عمرو شاخصا" وما أشبه ذلك.

وأما إن وأخواتها فإنها تنصب الاسم وترفع الخبر، وهي: إن، وأن، ولكن، وكأن، وليت، ولعل، تقول: إن زيدا قائم، وليت عمرا شاخص، وما أشبه ذلك, ومعنى إن وأن للتوكيد، ولكن للاستدراك، ms3 وكأن للتشبيه، وليت للتمني، ولعل للترجي والتوقع.

وأما ظننت وأخواتها فإنها تنصب المبتدأ والخبر على أنهما مفعولان لها، وهي: ظننت، وحسبت، وخلت، وزعمت، ورأيت، وعلمت، ووجدت، واتخذت، وجعلت، وسمعت؛ تقول: ظننت زيدا قائما، ورأيت عمرا شاخصا، وما أشبه ذلك.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 108;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 109, 'باب النعت', 'باب النعت');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'النعت: تابع للمنعوت في رفعه، ونصبه، وخفضه، وتعريفه، وتنكيره، تقول: قام زيد العاقل، ورأيت زيدا العاقل، ومررت بزيد العاقل.

والمعرفة خمسة أشياء: الاسم المضمر، نحو: أنا، وأنت، والاسم العلم، نحو: زيد ومكة، والاسم المبهم، نحو: هذا وهذه وهؤلاء، والاسم الذي فيه الألف واللام، نحو: الرجل والغلام، وما أضيف إلى واحد من هذه الأربعة.

والنكرة: كل اسم شائع في جنسه لا يختص به واحد دون آخر، وتقريبه كل ما صلح دخول الألف واللام عليه، نحو: الرجل والفرس.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 109;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 110, 'باب العطف', 'باب العطف');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وحروف العطف عشرة، وهي:

الواو، والفاء، وثم، وأو، وأم، وإما، وبل، ولا، ولكن، وحتى في بعض المواضع.

فإن عطفت بها على مرفوع رفعت1، أو على منصوب نصبت، أو على مخفوض خفضت، أو على مجزوم جزمت، تقول: "قام زيد وعمرو، ورأيت زيدا وعمرا، ومررت بزيد وعمرو، وزيد لم يقم ولم يقعد".', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 110;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 111, 'باب التوكيد', 'باب التوكيد');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'التوكيد: "تابع للمؤكد في رفعه، ونصبه، وخفضه، وتعريفه".

ويكون بألفاظ معلومة، وهي: النفس، والعين، وكل، وأجمع، وتوابع أجمع، وهي: أكتع، وأبتع، وأبصع، تقول: قام زيد نفسه، ورأيت القوم كلهم، ومررت بالقوم أجمعين.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 111;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 112, '[باب البدل]', '[باب البدل]');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'إذا أبدل اسم من اسم أو فعل من فعل تبعه في جميع إعرابه.

وهو أربعة أقسام 1:

بدل الشيء من الشيء، وبدل البعض من الكل، وبدل الاشتمال، وبدل الغلط، نحو قولك: "قام زيد أخوك، وأكلت الرغيف ثلثه، ونفعني زيد علمه، ورأيت زيدا الفرس"، أردت أن تقول: الفرس فغلطت فأبدلت زيدا منه.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 112;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 113, 'باب منصوبات الأسماء', 'باب منصوبات الأسماء');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'المنصوبات خمسة عشر، وهي: المفعول به، والمصدر، وظرف الزمان، وظرف المكان، والحال، والتمييز، والمستثنى، واسم لا، والمنادى، والمفعول من أجله، والمفعول معه، وخبر كان وأخواتها، واسم إن وأخواتها.

والتابع للمنصوب، وهو أربعة أشياء: النعت، والعطف، والتوكيد، والبدل.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 113;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 114, 'باب المفعول به', 'باب المفعول به');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وهو الاسم ms4 المنصوب الذي يقع به الفعل, نحو: ضربت زيدا، وركبت الفرس.

وهو قسمان: ظاهر , ومضمر.

فالظاهر ما تقدم ذكره.

والمضمر قسمان: متصل، ومنفصل.

فالمتصل اثنا عشر، وهي: ضربني، وضربنا، وضربك، وضربك، وضربكما، وضربكم، وضربكن، وضربه، وضربها، وضربهما، وضربهم، وضربهن.

والمنفصل اثنا عشر، وهي: إياي، وإيانا، وإياك، وإياك، وإياكما، وإياكم، وإياكن، وإياه، وإياها، وإياهما، وإياهم، وإياهن.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 114;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 115, 'باب المصدر', 'باب المصدر');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'المصدر: هو الاسم المنصوب, الذي يجيء ثالثا في تصريف الفعل، نحو: ضرب يضرب ضربا.

وهو قسمان: لفظي ومعنوي فإن وافق لفظه لفظ فعله فهو لفظي, نحو: قتلته قتلا.

وان وافق معنى فعله دون لفظه فهو معنوي، نحو: جلست قعودا، وقمت وقوفا، وما أشبه ذلك.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 115;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 116, 'باب ظرف الزمان وظرف المكان', 'باب ظرف الزمان وظرف المكان');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ظرف الزمان هو: اسم الزمان المنصوب بتقدير "في" نحو: اليوم، والليلة، وغدوة، وبكرة، وسحرا، وغدا، وعتمة، وصباحا، ومساء، وأبدا، وأمدا، وحينا، وما أشبه ذلك.

وظرف المكان هو: اسم المكان المنصوب بتقدير "في" نحو: أمام، وخلف، وقدام، ووراء، وفوق، وتحت، وعند، ومع، وإزاء، وحذاء، وتلقاء، وهنا، وثم، وما أشبه ذلك.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 116;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 117, 'باب الحال', 'باب الحال');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'الحال هو: الاسم المنصوب, المفسر لما انبهم من الهيئات، نحو قولك: "جاء زيد راكبا" و"ركبت الفرس مسرجا" و"لقيت عبد الله راكبا" وما أشبه ذلك.

ولا يكون الحال إلا نكرة، ولا يكون إلا بعد تمام الكلام، ولا يكون صاحبها إلا معرفة.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 117;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 118, 'باب التمييز', 'باب التمييز');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'التمييز هو: الاسم المنصوب, المفسر لما انبهم من الذوات، نحو قولك: "تصبب زيد عرقا"، و"تفقأ بكر شحما" و"طاب محمد نفسا" و"اشتريت عشرين غلاما" و"ملكت تسعين نعجة" و"زيد أكرم منك أبا" و"أجمل منك وجها".

ولا يكون إلا نكرة، ولا يكون إلا بعد تمام الكلام.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 118;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 119, 'باب الاستثناء', 'باب الاستثناء');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وحروف الاستثناء ثمانية , وهي: إلا، وغير، وسوى، وسوى، وسواء، وخلا، وعدا، وحاشا.

فالمستثنى بإلا ينصب إذا كان الكلام تاما موجبا، نحو: "قام القوم إلا زيدا" و"خرج الناس إلا عمرا".

وإن كان الكلام منفيا تاما جاز فيه البدل والنصب على الاستثناء، نحو: "ما قام إلا زيدا" و"إلا زيد".

وإن كان الكلام ناقصا كان على حسب العوامل، نحو: "ما ms5 قام إلا زيد" و"ما ضربت إلا زيدا" و"ما مررت إلا بزيد".

والمستثنى بغير, وسوى, وسوى، وسواء, مجرور لا غير.

والمستثنى بخلا، وعدا، وحاشا، يجوز نصبه وجره، نحو: "قام القوم خلا زيدا, وزيد" و"عدا عمرا وعمرو" و"حاشا بكرا وبكر".', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 119;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 120, 'باب لا', 'باب لا');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'اعلم أن "لا" تنصب النكرات بغير تنوين إذا باشرت النكرة ولم تتكرر "لا" نحو: "لا رجل في الدار".

فإن لم تباشرها وجب الرفع ووجب تكرار "لا" نحو: "لا في الدار رجل ولا امرأة".

فإن تكررت "لا" جاز إعمالها وإلغاؤها، فإن شئت قلت: "لا رجل في الدار ولا امرأة" وإن شئت قلت: "لا رجل في الدار ولا امرأة".', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 120;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 121, 'باب المنادى', 'باب المنادى');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'المنادى خمسة أنواع: المفرد العلم، والنكرة المقصودة، والنكرة غير المقصودة، والمضاف، والشبيه بالمضاف.

فأما المفرد العلم والنكرة المقصودة فيبنيان على الضم من غير تنوين، نحو: "يا زيد" و"يا رجل".

والثلاثة الباقية منصوبة لا غير.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 121;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 122, 'باب المفعول من أجله', 'باب المفعول من أجله');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وهو: الاسم المنصوب الذي يذكر بيانا لسبب وقوع الفعل، نحو قولك: "قام زيد إجلالا لعمرو" و"قصدتك ابتغاء معروفك".', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 122;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 123, 'باب المفعول معه', 'باب المفعول معه');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وهو: الاسم المنصوب الذي يذكر لبيان من فعل معه الفعل، نحو قولك: "جاء الأمير والجيش" و"استوى الماء والخشبة".

وأما خبر "كان" وأخواتها، واسم "إن" وأخواتها، فقد تقدم ذكرهما في المرفوعات، وكذلك التوابع فقد تقدمت هناك.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 123;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('jurumiyah', 124, 'باب المخفوضات من الأسماء', 'باب المخفوضات من الأسماء');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, '...

باب المخفوضات الأسماء

المخفوضات ثلاثة أنواع 1: مخفوض بالحرف، ومخفوض بالإضافة، وتابع للمخفوض.

فأما المخفوض بالحرف فهو: ما يخفض بمن، وإلى، وعن، وعلى، وفي، ورب، والباء، والكاف، واللام، وبحروف القسم، وهي: الواو، والباء، والتاء، وبواو رب، وبمذ، ومنذ.

وأما ما يخفض بالإضافة , فنحو قولك: "غلام زيد" وهو على قسمين: ما يقدر باللام، وما يقدر بمن، فالذي يقدر باللام، نحو: "غلام زيد" والذي يقدر بمن، نحو: "ثوب خز" و"باب ساج" و"خاتم حديد".

تم بحمد الله  ms6', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'jurumiyah' AND bab_order = 124;

