INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, '...

بسم الله الرحمن الرحيم

الحمد الله رب العالمين وصلى الله على سيدنا محمد النبي وآله الطاهرين وصحابته أجمعين.

قال القاضي أبو شجاع أحمد بن الحسين بن أحمد الأصفهاني رحمة الله تعالى: سألني بعض الأصدقاء حفظهم الله تعالى أن أعمل مختصرا في الفقه على مذهب الإمام الشافعي رحمة الله تعالى عليه ورضوانه في غاية الاختصار ونهاية الإيجاز ليقرب على المتعلم درسه ويسهل على المبتدئ حفظه. وأن أكثر فيه من التقسيمات وحصر الخصال فأجبته إلى ذلك طالبا للثواب راغبا إلى الله تعالى في التوفيق للصواب إنه على ما يشاء قدير

وبعباده لطيف خبير.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 100;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 101, 'كتاب الطهارة', 'كتاب الطهارة');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'المياه التي يجوز التطهير بها سبع مياه: ماء السماء, وماء البحر, وماء النهر, وماء البئر, وماء العين, وماء الثلج, وماء البرد. ثم المياه على أربعة أقسام: طاهر مطهر غير مكروه وهو الماء المطلق, وطاهر مطهر مكروه وهو الماء المشمس, وطاهر غير مطهر وهو الماء المستعمل والمتغير بما خالطه من الطاهرات, وماء نجس وهو الذي حلت فيه نجاسة وهو دون القلتين أو كان قلتين فتغير والقلتان: خمس مائة رطل بغدادي تقريبا في الأصح.

"فصل" وجلود الميتة تطهر بالدباغ إلا جلد الكلب والخنزير وما تولد منهما أو من أحدهما وعظم الميتة وشعرها نجس إلا الآدمي.

"فصل" ولا يجوز استعمال أواني الذهب والفضة ويجوز استعمال غيرهما من الأواني.

"فصل" والسواك مستحب في كل حال إلا بعد الزوال للصائم وهو في ثلاثة مواضع أشد استحبابا: عند تغير الفم من أزم وغيره وعند القيام من النوم وعند القيام إلى الصلاة.

"فصل" وفروض الوضوء ستة أشياء: النية عند غسل الوجه وغسل الوجه وغسل اليدين مع المرفقين ومسح بعض الرأس وغسل.

الرجلين إلى الكعبين والترتيب على ما ذكرناه وسننه عشرة أشياء: التسمية وغسل الكفين قبل إدخالهما الإناء والمضمضة والاستنشاق ومسح الأذنين ظاهرهما وباطنهما بماء جديد وتخليل اللحية الكثة وتخليل أصابع اليدين والرجلين وتقديم اليمنى على اليسرى والطهارة ثلاثا ثلاثا والموالاة.

"فصل" والاستنجاء واجب من البول والغائط والأفضل أن يستنجي بالأحجار ثم يتبعها بالماء ms01 ويجوز أن يقتصر على الماء أو على ثلاثة أحجار ينقي بهن المحل فإذا أراد الاقتصار على أحدهما فالماء أفضل ويجتنب استقبال القبلة واستدبارها في الصحراء ويجتنب البول والغائط في الماء الراكد وتحت الشجرة المثمرة وفي الطريق والظل والثقب ولا يتكلم على البول والغائط ولا يستقبل الشمس والقمر ولا يستدبرهما.

"فصل" والذي ينقض الوضوء ستة أشياء: ما خرج من السبيلين والنوم على غير هيئة المتمكن وزوال العقل بسكر أو مرض ولمس الرجل المرأة الأجنبية من غير حائل ومس فرج الآدمي بباطن الكف ومس حلقة دبره على الجديد.

"فصل" والذي يوجب الغسل ستة أشياء: ثلاثة تشترك فيها

الرجال والنساء وهي التقاء الختانين وإنزال المني والموت وثلاثة تختص بها النساء وهي الحيض والنفاس والولادة.

"فصل" وفرائض الغسل ثلاثة أشياء: النية وإزالة النجاسة إن كانت على بدنه وإيصال الماء إلى جميع الشعر والبشرة وسننه خمسة أشياء: التسمية والوضوء قبله وإمرار اليد على الجسد والموالاة وتقديم اليمنى على اليسرى.

"فصل" والاغتسالات المسنونة سبعة عشر غسلا: غسل الجمعة والعيدين والاستسقاء والخسوف والكسوف والغسل من غسل الميت والكافر إذا أسلم والمجنون والمغمى عليه إذا أفاقا والغسل عند الإحرام ولدخول مكة وللوقوف بعرفة وللمبيت بمزدلفة ولرمي الجمار الثلاث وللطواف وللسعي ولدخول مدينة الرسول صلى الله عليه وسلم.

"فصل" والمسح على الخفين جائز بثلاثة شرائط: أن يبتدئ لبسهما بعد كمال الطهارة وأن يكونا ساترين لمحل غسل الفرض من القدمين وأن يكونا مما يمكن تتابع المشي عليهما ويمسح المقيم يوما وليلة والمسافر ثلاثة أيام بلياليهن وابتداء المدة من حين يحدث بعد لبس الخفين فإن مسح في الحضر ثم سافر أو مسح في السفر ثم أقام أتم مسح مقيم ويبطل المسح بثلاثة أشياء: بخلعهما وانقضاء المدة وما يوجب الغسل.

"فصل" وشرائط التيمم خمسة أشياء: وجود العذر بسفر أو مرض ودخول وقت الصلاة وطلب الماء وتعذر استعماله وإعوازه بعد الطلب والتراب الطاهر له غبار فإن خالطه جص أو رمل لم يجز.

وفرائضه أربعة أشياء: النية ومسح اليدين مع المرفقين والترتيب وسننه ثلاثة ms02 أشياء: التسمية وتقديم اليمنى على اليسرى والموالاة, والذي يبطل التيمم ثلاثة أشياء: ما أبطل الوضوء ورؤية الماء في غير وقت الصلاة والردة وصاحب الجبائر يمسح عليها ويتمم ويصلي ولا إعادة عليه إن كان وضعها على طهر ويتيمم لكل فريضة ويصلي بتيمم واحد ما شاء من النوافل.

"فصل" وكل مائع خرج من السبيلين نجس إلا المني وغسل جميع الأبوال والأرواث واجب إلا بول الصبي الذي لم يأكل الطعام فإنه يطهر برش الماء عليه ولا يعفى عن شيء من النجاسات إلا اليسير من الدم والقيح وما لا نفس له سائلة إذا وقع في الإناء ومات فيه فإنه لا ينجسه والحيوان كله طاهر إلا الكلب والخنزير وما تولد منهما أو من أحدهما والميتة كلها نجسة إلا السمك والجراد والآدمي, ويغسل الإناء من ولوغ الكلب والخنزير سبع مرات إحداهن بالتراب ويغسل من سائر النجاسات مرة تأتي عليه والثلاث أفضل وإذا تخللت الخمرة بنفسها طهرت وإن خللت بطرح شيء فيها لم تطهر.

"فصل" ويخرج من الفرج ثلاثة دماء دم الحيض والنفاس والاستحاضة فالحيض هو الدم الخارج من فرج المرأة على سبيل الصحة من غير سبب الولادة ولونه أسود محتدم لذاع والنفاس هو الدم الخارج عقب الولادة والاستحاضة هو الدم الخارج في غير أيام الحيض والنفاس وأقل الحيض يوم وليلة وأكثره خمسة عشر يوما وغالبه ست أو سبع وأقل النفاس لحظه وأكثره ستون يوما وغالبه أربعون يوما وأقل الطهر بين الحيضتين خمسة عشر يوما ولا حد لأكثره وأقل زمن تحيض فيه المرأة تسع سنين وأقل الحمل ستة أشهر وأكثره أربع سنين وغالبه تسعة أشهر, ويحرم بالحيض والنفاس ثمانية أشياء: الصلاة والصوم وقراءة القرآن ومس المصحف وحمله ودخول المسجد والطواف والوطء والاستمتاع بما بين السرة والركبة, ويحرم على الجنب خمسة أشياء الصلاة وقراءة القرآن ومس المصحف وحمله والطواف واللبث في المسجد, ويحرم على المحدث ثلاثة أشياء الصلاة والطواف ومس المصحف وحمله.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 101;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 102, 'كتاب الصلاة', 'كتاب الصلاة');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'الصلاة المفروضة خمس الظهر وأول وقتها زوال الشمسوآخره إذا صار ظل كل شيء مثله ms03 بعد ظل الزوال والعصر وأول وقتها الزيادة على ظل المثل وآخره في الاختيار إلى ظل المثلين وفي الجواز إلى غروب الشمس والمغرب ووقتها واحد وهو غروب الشمس وبمقدار مايؤذن ويتوضأ ويستر العورة ويقيم الصلاة ويصلي خمس ركعات والعشاء وأول وقتها إذا غاب الشفق الأحمر وآخره في الاختيار إلى ثلث الليل وفي الجواز إلى طلوع الفجر الثاني والصبح وأول وقتها طلوع الفجر الثاني وآخره في الاختيار إلى الأسفار وفي الجواز إلى طلوع الشمس.

"فصل" وشرائط وجوب الصلاة ثلاثة أشياء: الإسلام والبلوغ والعقل وهو حد التكليف والصلوات المسنونة خمس العيدان والكسوفان والاستسقاء, والسنن التابعة للفرائض سبعة عشر ركعة ركعتا الفجر وأربع قبل الظهر وركعتان بعده وأربع قبل العصر وركعتان بعد المغرب وثلاث بعد العشاء يوتر بواحدة منهن وثلاث نوافل مؤكدات صلاة الليل وصلاة الضحى وصلاة التراويح.

"فصل" وشرائط الصلاة قبل الدخول فيها خمسة أشياء طهارة الأعضاء من الحدث والنجس وستر العورة بلباس طاهر والوقوف على مكان طاهر والعلم بدخول الوقت واستقبال القبلة ويجوز ترك

القبلة في حالتين في شدة الخوف وفي النافلة في السفر على الراحلة.

"فصل" وأركان الصلاة ثمانية عشر ركنا النية والقيام مع القدرة وتكبيرة الإحرام وقراءة الفاتحة وبسم الله الرحمن الرحيم آية منها والركوع والطمأنينة فيه والرفع واعتدال والطمأنينة فيه والسجود والطمأنينة فيه والجلوس بين السجدتين والطمأنينة فيه والجلوس الأخير والتشهد فيه والصلاة على النبي صلى الله عليه وسلم فيه والتسليمة الأولى ونية الخروج من الصلاة وترتيب الأركان على ما ذكرناه, وسننها قبل الدخول فيها شيئان الأذان والإقامة وبعد الدخول فيها شيئان التشهد الأول والقنوت في الصبح وفي الوتر في النصف الثاني من شهر رمضان, وهيأتها خمسة عشر خصلة رفع اليدين عند تكبيرة الإحرام وعند الركوع والرفع منه ووضع اليمين على الشمال والتوجه والاستعاذة والجهر في موضعه والإسرار في موضعه والتأمين وقراءة سورة بعد الفاتحة والتكبيرات عند الرفع والخفض وقول سمع الله لمن حمده ربنا لك الحمد والتسبيح في الركوع والسجود ووضع اليدين على الفخذين في الجلوس يبسط اليسرى ms04 ويقبض اليمنى إلا المسبحة فإنه يشير بها متشهدا والافتراش في جميع الجلسات والتورك في الجلسة الأخيرة والتسليمة الثانية.

"فصل" والمرأة تخالف الرجل في خمسة أشياء: فالرجل يجافي مرفقيه عن جنبيه ويقل بطنه عن فخذيه في الركوع والسجود ويجهر في مواضع الجهر وإذا نابه شيء في الصلاة سبح وعورةالرجل ما بين سرته وركبته والمرأة تضم بعضها إلى بعض وتخفض صوتها بحضرة الرجال الأجانب وإذا نابها شيء في الصلاة صفقت وجميع بدن الحرة عورة إلا وجهها وكفيها والأمة كالرجل.

"فصل" والذي يبطل الصلاة أحد عشر شيئا الكلام العمد والعمل الكثير والحدث وحدوث النجاسة وانكشاف العورة وتغير النية واستدبار القبلة والأكل والشرب والقهقهة والردة.

"فصل" وركعات الفرائض سبعة عشر ركعة فيها أربع وثلاثون سجدة وأربع وتسعون تكبيرة وتسع تشهدات وعشر تسليمات ومائة وثلاث وخمسون تسبيحة وجملة الأركان في الصلاة مائة وستة وعشرون ركنا في الصبح وثلاثون ركنا وفي المغرب اثنان وأربعون ركنا وفي الرباعية أربعة وخمسون ركنا ومن عجز عن القيام في الفريضة صلى جالسا ومن عجز عن الجلوس صلى مضطجعا.

"فصل" والمتروك من الصلاة ثلاثة أشياء فرض وسنة وهيئة فالفرض لا ينوب عنه سجود السهو بل إن ذكره والزمان قريب

أتى به وبنى عليه وسجد للسهو والسنة لا يعود إليها بعد التلبس بالفرض لكنه يسجد للسهو عنها والهيئة لا يعود إليها بعد تركها ولا يسجد للسهو عنها وإذا شك في عدد ما أتى به من الركعات بنى على اليقين وهو الأقل وسجد للسهو وسجود السهو سنة ومحله قبل السلام.

"فصل" وخمسة أوقات لا يصلى فيها إلا صلاة لها سبب بعد صلاة الصبح حتى تطلع الشمس وعند طلوعها حتى تتكامل وترتفع قدر رمح وإذا استوت حتى تزول وبعد صلاة العصر حتى تغرب الشمس وعند الغروب حتى يتكامل غروبها.

"فصل" وصلاة الجماعة سنة مؤكدة وعلى المأموم أن ينوي الائتمام دون الإمام ويجوز أن يأتم الحر بالعبد والبالغ بالمراهق ولا تصح قدوة رجل بامرأة ولا قارئ بأمي وأي موضع صلى في المسجد بصلاة الإمام فيه ms05 وهو عالم بصلاته أجزئه ما لم يتقدم عليه وإن صلى خارج المسجد والمأموم قريبا منه وهو عالم بصلاته ولا حائل هناك جاز.

"فصل" ويجوز للمسافر قصر الصلاة الرباعية بخمس شرائط أن يكون سفره في غير معصية وأن يكون مسافته ستة عشر فرسخا بلا إياب وأن يكون مؤديا للصلاة الرباعية وأن ينوي القصر مع

الإحرام وأن لا يأتم بمقيم ويجوز للمسافر أن يجمع بين الظهر والعصر في وقت أيهما شاء وبين المغرب والعشاء في وقت أيهما شاء ويجوز للحاضر في المطر أن يجمع بينهما في وقت الأولى منهما.

"فصل" وشرائط وجوب الجمعة سبعة أشياء: الإسلام والبلوغ والعقل والحرية والذكورية والصحة والاستيطان, وشرائط فعلها ثلاثة أن تكون البلد مصرا أو قرية وأن يكون العدد أربعين من أهل الجمعة وأن يكون الوقت باقيا فإن خرج الوقت أو عدمت الشروط صليت ظهرا وفرائضها ثلاثة خطبتان يقوم فيهما ويجلس بينهما وأن تصلى ركعتين في جماعة وهيأتها أربع خصال: الغسل وتنظيف الجسد ولبس الثياب البيض وأخذ الظفر والطيب ويستحب الإنصات في وقت الخطبة ومن دخل والإمام يخطب صلى ركعتين خفيفتين ثم يجلس.

"فصل" وصلاة العيدين سنة مؤكدة وهي ركعتان يكبر في الأولى سبعا سوى تكبيرة الإحرام وفي الثانية خمسا سوى تكبيرة القيام ويخطب بعدها خطبتين يكبر في الأولى تسعا وفي الثانية سبعا ويكبر من غروب الشمس من ليلة العيد إلى أن يدخل الإمام في الصلاة وفي الأضحى خلف الصلوات المفروضات

من صبح يوم عرفة إلى العصر من آخر أيام التشريق.

"فصل" وصلاة الكسوف سنة مؤكدة فإن فاتت لم تقض ويصلي لكسوف الشمس وخسوف القمر ركعتين في كل ركعة قيامان يطيل القراءة فيهما وركوعان يطيل التسبيح فيهما دون السجود ويخطب بعدها خطبتين ويسر في كسوف الشمس ويجهر في خسوف القمر.

"فصل" وصلاة الاستسقاء مسنونة فيأمرهم الإمام بالتوبة والصدقة والخروج من المظالم ومصالحة الأعداء وصيام ثلاثة أيام ثم يخرج بهم في اليوم الرابع في ثياب بذلة واستكانة وتضرع ويصلي بهم ركعتين كصلاة العيدين ثم يخطب بعدهما ويحول رداءه ms06 ويكثر من الدعاء والاستغفار ويدعو بدعاء رسول الله صلى الله عليه وسلم وهو: اللهم اجعلها سقيا رحمة ولا تجعلها سقيا عذاب ولا محق ولا بلاء ولا هدم ولا غرق اللهم على الظراب والآكام ومنابت الشجر وبطون الأودية اللهم حوالينا ولا علينا اللهم اسقنا غيثا مغيثا هنيئا مريئا مريعا سحا عاما غدقا طبقا مجللا دائما إلى يوم الدين اللهم اسقنا الغيث ولا تجعلنا من القانطين اللهم إن بالعباد والبلاد من الجهد والجوع والضنك ما لا نشكو إلا إليك اللهم أنبت لنا الزرع

وأدر لنا الضرع وأنزل علينا من بركات السماء وأنبت لنا من بركات الأرض واكشف عنا من البلاء ما لا يكشفه غيرك اللهم إنا نستغفرك إنك كنت غفارا فأرسل السماء علينا مدرارا, ويغتسل في الوادي إذا سال ويسبح للرعد والبرق.

"فصل" وصلاة الخوف على ثلاثة أضرب أحدهما أن يكون العدو في غير جهة القبلة فيفرقهم الإمام فرقتين فرقة تقف في وجه العدو وفرقة خلفه فيصلي بالفرقة التي خلفه ركعة ثم تتم لنفسها وتمضي إلى وجه العدو وتأتي الطائفة الأخرى فيصلي بها ركعة ثم تتم لنفسها ويسلم بها والثاني أن يكون العدو في جهة القبلة فيصفهم الإمام صفين ويحرم بهم فإذا سجد سجد معه أحد الصفين ووقف الصف الآخر يحرسهم فإذا رفع سجدوا ولحقوه والثالث أن يكون في شدة الخوف والتحام الحرب فيصلي كيف أمكنه راجلا أو راكبا مستقبل القبلة وغير مستقبل لها.

"فصل" ويحرم على الرجال لبس الحرير والتختم بالذهب ويحل للنساء وقليل الذهب وكثيره في التحريم سواء وإذا كان بعض الثوب إبريسما وبعضه قطنا أو كتانا جاز لبسه ما لم يكن الإبريسم غالبا.

"فصل" ويلزم في الميت أربعة أشياء: غسله وتكفينه والصلاة

عليه ودفنه واثنان لا يغسلان ولا يصلي عليهما الشهيد في معركة المشركين والسقط الذي لم يستهل صارخا ويغسل الميت وترا ويكون في أول غسله سدر وفي آخره شيء من كافور ويكفن في ثلاثة أثواب بيض ليس فيها قميص ولا عمامة ويكبر عليه أربع تكبيرات يقرأ الفاتحة بعد ms07 الأولى ويصلي على النبي صلى الله عليه وسلم بعد الثانية ويدعو للميت بعد الثالثة فيقول اللهم هذا عبدك وابن عبديك خرج من روح الدنيا وسعتها ومحبوبه وأحبائه فيها إلى ظلمة القبر وما هو لاقيه كان يشهد ألا إله إلا أنت وحدك لا شريك لك وأن محمدا عبدك ورسولك وأنت أعلم به منا اللهم إنه نزل بك وأنت خير منزو ل به وأصبح فقيرا إلى رحمتك وأنت غني عن عذابه وقد جئناك راغبين إليك شفعاء له اللهم إن كان محسنا فزد في إحسانه وإن كان مسيئا فتجاوز عنه ولقه برحمتك رضاك وقه فتنة القبر وعذابه وافسح له في قبره وجاف الأرض عن جنبيه ولقه برحمتك الأمن من عذابك وحتى تبعثه آمنا إلى جنتك يا أرحم الراحمين, ويقول بعد الرابعة اللهم لا تحرمنا أجره ولا تفتنا بعده واغفر لنا وله, ويسلم بعد الرابعة ويدفن في لحد مستقبل القبلة ويسل من قبل رأسه برفق ويقول الذي يلحده: بسم الله وعلى ملة رسول الله صلى الله عليه وسلم ويضجع في

القبر بعد أن يعمق قامة وبسطة ويسطح القبر ولا يبنى عليه ولا يجصص ولا بأس بالبكاء على الميت من غير نوح ولا شق جيب ويعزى أهله إلى ثلاثة أيام من دفنه ولا يدفن اثنان في قبر إلا لحاجة.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 102;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 103, 'كتاب الزكاة', 'كتاب الزكاة');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'تجب الزكاة في خمسة أشياء وهي: المواشي والأثمان والزروع والثمار وعروض التجارة فأما المواشي فتجب الزكاة في ثلاثة أجناس منها وهي: الإبل والبقر والغنم وشرائط وجوبها ستة أشياء الإسلام والحرية والملك التام والنصاب والحول والسوم وأما الأتمان فشيئان الذهب والفضة وشرائط وجوب الزكاة فيها خمسة أشياء الإسلام والحربة والملك التام والنصاب والحول وأما الزروع فتجب الزكاة فيها بثلاثة شرائط أن يكون مما يزرعه الآدميون وأن يكون قوتا مدخرا وأن يكون نصابا وهو خمسة أوسق لا قشر عليها وأما الثمار فتجب الزكاة في شيئين منها ثمرة النخل وثمرة الكرم وشرائط وجوب الزكاة فيها أربعة أشياء الإسلام والحرية والملك التام والنصاب وأما عروض التجارة فتجب الزكاة ms08 فيها بالشرائط المذكورة في الأثمان.

"فصل" وأول نصاب الإبل خمس وفيها شاة وفي عشر شاتان

وفي خمس عشرة ثلاث شياة وفي عشرين أربع شياة وفي خمس وعشرين بنت مخاض وفي ست وثلاثين بنت لبون وفي ست وأربعين حقة وفي إحدى وستين جذعة وفي ست وسبعين بنتا لبون وفي إحدى وتسعين حقتان وفي مائة وإحدى وعشرين ثلاث بنات لبون ثم في كل أربعين بنت لبون وفي كل خمسين حقة.

"فصل" وأول نصاب البقر ثلاثون وفيها تبيع وفي أربعين مسنة وعلى هذا فقس.

"فصل" وأول نصاب الغنم أربعون وفيها شاة جذعة من الضأن أو ثنية من المعز وفي مائة وإحدى وعشرين شاتان وفي مائتين وواحدة ثلاث شياة وفي أربعمائة أربع شياة ثم في كل مائة شاة.

"فصل" والخليطان يزكيان زكاة الواحد بسبعة شرائط: إذا كان المراح واحدا والمسرح واحدا والمرعى واحدا والفحل واحدا والمشرب واحدا والحالب واحدا وموضع الحلب واحدا.

"فصل" ونصاب الذهب عشرون مثقالا وفيه ربع العشر وهو نصف مثقال وفيما زاد بحسابه ونصاب الورق مائتا درهم وفيه ربع العشر وهو خمسة دراهم وفيما زاد بحسابه ولا تجب في الحلي المباح زكاة.

"فصل" ونصاب الزروع والثمار خمسة أو سق وهي ألف وستمائة رطل بالعراقي وفيما زاد بحسابه وفيها إن سقيت بماء السماء

أو السيح العشر وإن سقيت بدولاب أو نضح نصف العشر.

"فصل" وتقوم عروض التجارة عند آخر الحول بما اشتريت به ويخرج من ذلك ربع العشر وما استخرج من معادن الذهب والفضة بخرج منه ربع العشر في الحال وما يوجد من الركاز ففيه الخمس.

"فصل" وتجب زكاة الفطر بثلاثة أشياء الإسلام وبغروب الشمس من آخر يوم من شهر رمضان ووجود الفضل عن قوته وقوت عياله في ذلك اليوم ويزكي عن نفسه وعمن تلزمه نفقته من المسلمين صاعا من قوت بلده وقدره خمسة أرطال وثلث بالعراقي.

"فصل" وتدفع الزكاة إلى الأصناف الثمانية الذين ذكرهم الله تعالى في كتابه العزيز في قوله تعالى: {إنما الصدقات للفقراء والمساكين والعاملين عليها والمؤلفة قلوبهم وفي ms09 الرقاب والغارمين وفي سبيل الله وابن السبيل} وإلى من يوجد منهم ولا يقتصر على أقل من ثلاثة من كل صنف إلا العامل وخمسة لا يجوز دفعها إليهم الغني بمال أو كسب والعبد وبنو هاشم وبنو المطلب والكافر ومن تلزم المزكي نفقته لا يدفعها إليهم باسم الفقراء والمساكين.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 103;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 104, 'كتاب الصوم', 'كتاب الصوم');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وشرائط وجوب الصيام أربعة أشياء الإسلام والبلوغ والعقل

والقدرة على الصوم, وفرائض الصوم أربعة أشياء النية والإمساك عن الأكل والشرب والجماع وتعمد القيء, والذي يفطر به الصائم عشرة أشياء: ما وصل عمدا إلى الجوف أو الرأس والحقنة في أحد السبيلين والقيء عمدا والوطء عمدا في الفرج والإنزال عن مباشرة والحيض والنفاس والجنون والإغماء كل اليوم والردة, ويستحب في الصوم ثلاثة أشياء تعجيل الفطر وتأخير السحور وترك الهجر من الكلام ويحرم صيام خمسة أيام العيدان وأيام التشريق الثلاثة ويكره صوم يوم الشك إلا أن يوافق عادة له أو يصله بما قبله ومن وطئ في نهار رمضان عامدا في الفرج فعليه القضاء والكفارة وهي عتق رقبة مؤمنة فإن لم يجد فصيام شهرين متتابعين فإن لم يستطع فإطعام ستين مسكينا لكل مسكين مد ومن مات وعليه صيام من رمضان أطعم عنه لكل يوم مد والشيخ إذا عجز عن الصوم يفطر ويطعم عن كل يوم مدا والحامل والمرضع إن خافتا على أنفسهما أفطرتا وعليهما القضاء وإن خافتا على أولادهما أفطرتا وعليهما القضاء والكفارة عن كل يوم مد وهو رطل وثلث بالعراقي والمريض والمسافر سفرا طويلا يفطران ويقضيان.

"فصل" والاعتكاف سنة مستحبة وله شرطان: النية واللبث في المسجد ولا يخرج من الاعتكاف المنذور إلا لحاجة الإنسان أو عذر من حيض أو مرض لا يمكن المقام معه ويبطل بالوطء.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 104;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 105, 'كتاب الحج', 'كتاب الحج');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وشرائط وجوب الحج سبعة أشياء: الإسلام والبلوغ والعقل والحرية ووجود الزاد والراحلة وتخلية الطريق وإمكان المسير, وأركان الحج أربعة: الإحرام مع النية والوقوف بعرفة والطواف بالبيت والسعي بين الصفا والمروة وأركان العمرة اربعة الإحرام والطواف والسعي والحلق أو التقصير في أحد القولين, وواجبات الحج غير الأركان ms10 ثلاثة: الإحرام من الميقات ورمي الجمار الثلاث والحلق, وسنن الحج سبع الإفراد وهو تقديم الحج على العمرة والتلبية وطواف القدوم والمبيت بمزدلفة وركعتا الطواف والمبيت بمنى وطواف الوداع ويتجرد الرجل عند الإحرام من المخيط ويلبس إزارا ورداء أبيضين.

"فصل" ويحرم على المحرم عشرة أشياء: لبس المخيط وتغطية الرأس من الرجل والوجه من المرأة وترجيل الشعر وحلقه وتقليم الأظفار والطيب وقتل الصيد وعقد النكاح والوطء والمباشرة بشهوة وفي جميع ذلك الفدية إلا عقد النكاح فإنه لا ينعقد ولا يفسده إلا الوطء في الفرج ولا يخرج منه بالفساد ومن فاته الوقوف بعرفة تحلل بعمل عمرة وعليه القضاء والهدي ومن ترك ركنا لم يحل من إحرامه حتى يأتي به

ومن ترك واجبا لزمه الدم ومن ترك سنة لم يلزمه بتركها شيء.

"فصل" والدماء الواجبة في الإحرام خمسة أشياء أحدها الدم الواجب بترك نسك وهو على الترتيب شاة فإن لم يجد فصيام عشرة أيام ثلاثة في الحج وسبعة إذا رجع إلى أهله والثاني الدم الواجب بالحلق والترفه وهو على التخيير شاة أو صوم ثلاثة أيام أو التصديق بثلاثة آصع على ستة مساكين والثالث الدم الواجب بإحصار فيتحلل ويهدي شاة والرابع الدم الواجب بقتل الصيد وهو على التخيير إن كان الصيد مما له مثل أخرج المثل من النعم أو قومه واشترى بقيمته طعاما وتصدق به أو صام عن كل مد يوما وإن كان الصيد مما لا مثل له أخرج بقيمته طعاما أو صام عن كل مد يوما والخامس الدم الواجب بالوطء وهو على الترتيب بدنة فإن لم يجدها فبقرة فإن لم يجدها فسبع من الغنم فإن لم يجدها قوم البدنة واشترى بقيمتها طعاما وتصدق به فإن لم يجد صام عن كل مد يوما ولا يجزئه الهدي ولا الإطعام إلا بالحرم ويجزئه أن يصوم حيث شاء ولا يجوز قتل صيد الحرم ولا قطع شجره والمحل والمحرم في ذلك سواء.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 105;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 106, 'كتاب البيوع وغيرها من المعاملات', 'كتاب البيوع وغيرها من المعاملات');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'البيوع ثلاثة أشياء: بيع عين مشاهدة فجائز وبيع شيء

موصوف في الذمة ms11 فجائز إذا وجدت الصفة على ما وصف به وبيع عين غائبة لم تشاهد ولم توصف فلا يجوز ويصح بيع كل طاهر منتفع به مملوك ولا يصح بيع عين نجسة ولا ما لا منفعة فيه.

"فصل" والربا في الذهب والفضة والمطعومات فلا يجوز بيع الذهب بالذهب ولا الفضة كذلك إلا متماثلا نقدا ولا بيع ما ابتاعه حتى يقبضه ولا بيع اللحم بالحيوان ويجوز بيع الذهب بالفضة متفاضلا نقدا وكذلك المطعومات لا يجوز بيع الجنس منها بمثله إلا متماثلا نقدا ويجوز بيع الجنس منها بغيره متفاضلا نقدا ولا يجوز بيع الغرر.

"فصل" والمتبايعان بالخيار ما لم يتفرقا ولهما أن يشترطا الخيار إلى ثلاثة أيام وإذا وجد بالمبيع عيب فللمشتري رده ولا يجوز بيع الثمرة مطلقا إلا بعد بدو صلاحها ولا بيع ما فيه الربا بجنسه رطبا إلا اللبن.

"فصل" ويصح السلم حالا ومؤجلا فيما تكامل فيه خمس شرائط أن يكون مضبوطا بالصفة وأن يكون جنسا لم يختلط به غيره ولم تدخله النار لإحالته وأن لا يكون معينا ولا من معين ثم لصحة السلم فيه ثمانية شرائط وهو أن يصفه بعد ذكر جنسه ونوعه بالصفات التي يختلف بها الثمن وأن يذكر قدره بما ينفي الجهالة عنه وإن كان مؤجلا ذكر وقت محله وأن يكون موجودا عند الاستحقاق في الغالب وأن يذكر موضع قبضه وأن يكون الثمن معلوما وأن

يتقابضا قبل التفرق وأن يكون عقد السلم ناجزا لا يدخله خيار الشرط.

"فصل" وكل ما جاز بيعه جاز رهنه في الديون إذا استقر ثبوتها في الذمة وللراهن الرجوع فيه ما لم يقبضه ولا يضمنه المرتهن إلا بالتعدي وإذا قبض بعض الحق لم يخرج شيء من الرهن حتى يقضى جميعه.

"فصل" والحجر على ستة الصبي والمجنون والسفيه المبذر لماله والمفلس الذي ارتكبته الديون والمريض فيما زاد على الثلث والعبد الذي لم يؤذن له في التجارة وتصرف الصبي والمجنون والسفيه غير صحيح وتصرف المفلس يصح في ذمته دون أعيان ماله وتصرف المريض فيما زاد على الثلث موقوف ms12 على إجازة الورثة من بعده وتصرف العبد يكون في ذمته يتبع به بعد عتقه.

"فصل" ويصح الصلح مع الإقرار في الأموال وما أفضي إليها وهو نوعان: إبراء ومعاوضة فالإبراء اقتصاره من حقه على بعضه ولا يجوز تعليقه على شرط والمعاوضة عدوله عن حقه إلى غيره ويجري عليه حكم البيع ويجوز للإنسان أن يشرع روشنا في طريق نافذ بحيث لا يتضرر المار به ولا يجوز في الدرب المشترك إلا بإذن الشركاء ويجوز تقديم الباب في الدرب المشترك ولا يجوز تأخيره إلا بإذن الشركاء.

"فصل" وشرائط الحوالة أربعة أشياء رضا المحيل وقبول

المحتال وكون الحق مستقرا في الذمة واتفاق ما في ذمة المحيل والمحال عليه في الجنس والنوع والحلول والتأجيل وتبرأ بها ذمة المحيل.

"فصل" ويصح ضمان الديون المستقرة في الذمة إذا علم قدرها ولصاحب الحق مطالبة من شاء من الضامن والمضمون عنه إذا كان الضمان على ما بينا وإذا غرم الضامن رجع على المضمون عنه إذا كان الضمان والقضاء بإذنه ولا يصح ضمان المجهول ولا ما لم يجب إلا درك المبيع.

"فصل" والكفالة بالبدن جائزة إذا كان على المكفول به حق لآدمي.

"فصل" وللشركة خمس شرائط: أن يكون على ناض من الدراهم والدنانير وأن يتفقا في الجنس والنوع وأن يخلطا المالين وأن يأذن كل واحد منهما لصاحبه في التصرف وأن يكون الربح والخسران على قدر المالين ولكل واحد منهما فسخها متى شاء وإذا مات أحدهما أو بطلت.

"فصل" وكل ما جاز للإنسان التصرف فيه بنفسه جاز له أن يوكل فيه أو يتوكل والوكالة عقد جائز لكل منهما فسخها متى شاء وتنفسخ بموت أحدهما والوكيل أمين فيما يقبضه وفيما يصرفه ولا يضمن إلا بالتفريط, ولا يجوز أن يبيع ويشتري إلا بثلاثة شرائط أن يبيع بثمن المثل وأن يكون نقدا بنقد البلد ولا يجوز

أن يبيع من نفسه ولا يقر على موكله.

"فصل" والمقر به ضربان حق الله تعالى وحق لآدمي فحق الله تعالى يصح الرجوع فيه عن الإقرار به وحق الآدمي لا ms13 يصح الرجوع فيه عن الإقرار به, وتفتقر صحة الإقرار إلى ثلاثة شرائط: البلوغ والعقل والاختيار وإن كان بمال اعتبر فيه شرط رابع وهو الرشد, وإذا أقر بمجهول رجع إليه في بيانه ويصح الاستثناء في الإقرار إذا وصله به وهو في حال الصحة والمرض سواء.

"فصل" وكل ما يمكن الانتفاع به مع بقاء عينه جازت إعارته إذا كانت منافعه آثارا وتجوز العارية مطلقة ومقيدة بمدة وهي مضمونة على المستعير بقيمتها يوم تلفها.

"فصل" ومن غصب مالا لأحد لزمه رده وأرش نقصه وأجرة مثله فإن تلف ضمنه بمثله إن كان له مثل وبقيمته إن لم يكن له مثل أكثر ما كانت من يوم الغصب إلى يوم التلف.

"فصل" والشفعة واجبة بالخلطة دون الجوار فيما ينقسم دون ما لا ينقسم وفي كل ما لا ينقل من الأرض كالعقار وغيره بالثمن الذي وقع عليه البيع وهي على الفور فإن أخرها مع القدرة عليها بطلت

وإذا تزوج امرأة على شقص أخذه الشفيع بمهر المثل وإذا كان الشفعاء جماعة استحقوها على قدر الأملاك.

"فصل" وللقراض أربعة شرائط أن يكون إلى ناض من الدراهم والدنانير وأن يأذن رب المال للعامل في التصرف مطلقا أو فيما لا ينقطع وجوده غالبا وان يشرط له جزءا معلوما من الربح وأن لا يقدر بمدة

ولا ضمان على العامل إلا بعدوان وإذا حصل ربح وخسران جبر الخسران بالربح.

"فصل" والمساقاة جائزة على النخل والكرم ولها شرطان: "أحدهما" أن يقدرها بمدة معلومة" والثاني" أن يعين للعامل جزءا معلوما من الثمرة ثم العمل فيها على ضربين عمل يعود نفعه إلى الثمرة فهو على العامل وعمل يعود نفعه إلى الأرض فهو على رب المال.

"فصل" وكل ما أمكن الانتفاع به مع بقاء عينه صحت إجارته إذا قدرت منفعته بأحد أمرين بمدة أو عمل وإطلاقها يقتضي تعجيل الأجرة إلا أن يشرط التأجيل ولا تبطل الإجارة بموت أحد المتعاقدين وتبطل بتلف العين المستأجرة ولا ضمان على الأجير إلا بعدوان.

"فصل" والجعالة جائزة وهو أن يشترط في رد ms14 ضالته عوضا معلوما فإذا ردها راد استحق ذلك العوض المشروط.

"فصل" وإذا دفع إلى رجل أرضا ليزرعها وشرط له جزءا معلوما من زرعها لم يجز وإن أكراه إياها بذهب أو فضة أو شرط له طعاما معلوما في ذمته جاز.

"فصل" وإحياء الموات جائز بشرطين أن يكون المحيي مسلما وأن تكون الأرض حرة لم يجر عليها ملك لمسلم وصفة الإحياء ما كان في العادة عمارة للمحيا ويجب بذل الماء بثلاثة شرائط أن يفضل عن حاجته وأن يحتاج إليه غيره لنفسه أو لبهيمته وأن يكون مما يستخلف في بئر أو عين.

"فصل" والوقف جائز بثلاثة شرائط أن يكون مما ينتفع به مع بقاء عينه وأن يكون على أصل موجود وفرع لا ينقطع وأن لا يكون في محظور وهو على ما شرط الواقف من تقديم أوتأخير أو تسويه أوتفضيل.

"فصل" وكل ما جاز بيعه جازت هبته ولا تلزم الهبة إلا بالقبض وإذا قبضها الموهوب له لم يكن للواهب أن يرجع فيها إلا أن يكون والدا وإذا أعمر شيئا أو أرقبه كان للمعمر أو للمرقب ولورثته من بعده.

"فصل" وإذا وجد لقطة في موات أو طريق فله أخذها أو تركها وأخذها أولى من تركها إن كان على ثقة من القيام بها وإذا أخذها وجب عليه أن يعرف ستة أشياء وعاءها وعفاصها ووكاءها وجنسها وعددها ووزنها ويحفظها في حرز مثلها ثم إذا أراد تملكها عرفها سنة على أبواب المساجد وفي الموضع الذي وجدها فيه فإن لم يجد صاحبها كان له أن يتملكها بشرط الضمان واللقطة على أربعة أضرب أحدها ما يبقى على الدوام فهذا حكمه الثاني ما لا يبقى كالطعام الرطب فهو مخير بين

أكله وغرمه أو بيعه وحفظ ثمنه الثالث ما يبقى بعلاج كالرطب فيفعل ما فيه المصلحة من بيعه وحفظ ثمنه أو تجفيفه وحفظه الرابع ما يحتاج إلى نفقة كالحيوان وهو ضربان حيوان لا يمتنع بنفسه فهو مخير بين أكله وغرم ثمنه أو تركه والتطوع بالإنفاق عليه أو بيعه وحفظ ثمنه, وحيوان يمتنع ms15 بنفسه فإن وجده في الصحراء تركه وإن وجده في الحضر فهو مخير بين الأشياء الثلاثة فيه.

"فصل" وإذا وجد لقيط بقارعة الطريق فأخذه وتربيته وكفالته واجبة على الكفاية ولا يقر إلا في يد أمين فإن وجد معه مال أنفق عليه الحاكم منه وإن لم يوجد معه مال فنفقته في بيت المال.

"فصل" والوديعة أمانة ويستحب قبولها لمن قام بالأمانة فيها ولا يضمن إلا بالتعدي وقول المودع مقبول في ردها على المودع وعليه أن يحفظها في حرز مثلها وإذا طولب بها فلم يخرجها مع القدرة عليها حتى تلفت ضمن.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 106;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 107, 'كتاب الفرائض والوصايا', 'كتاب الفرائض والوصايا');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'الوارثون من الرجال عشرة: الابن وابن الابن وإن سفل والأب والجد وإن علا والأخ وأبن الأخ وإن تراخى والعم وابن العم وإن تباعدا والزوج والمولى المعتق, الوارثات من النساء سبع البنت وبنت الابن

والأم والجدة والأخت والزوجة والمولاة المعتقة  ومن لا يسقط بحال خمسة: الزوجان والأبوان وولد الصلب  ومن لا يرث بحال سبعة: العبد والمدبر وأم الولد والمكاتب والقاتل والمرتد وأهل ملتين وأقرب العصبات الابن ثم ابنه ثم الأب ثم أبوه ثم الأخ للأب والأم ثم الأخ للأب ثم ابن الأخ للأب والأم ثم ابن الأخ للأب ثم العم على هذا الترتيب ثم ابنه فإن عدمت العصبات فالمولى المعتق.

"فصل" والفروض المذكورة في كتاب الله تعالى ستة النصف والربع والثمن والثلثان والثلث والسدس

فالنصف فرض خمسة البنت وبنت الابن والأخت من الأب والأم والأخت من الأب والزوج إذا لم يكن معه ولد والربع فرض اثنين الزوج مع الولد أو ولد الابن وهو فرض الزوجة والزوجات مع عدم الولد أو ولد الابن والثمن فرض الزوجة والزوجات مع الولد أو ولد الابن والثلثان فرض أربعة البنتين وبنتي الابن والأختين من الأب والأم والأختين من الأب والثلث فرض اثنين الأم إذا لم تحجب وهو للاثنين فصاعدا من الأخوة والأخوات من ولد الأم والسدس فرض سبعة الأم مع الولد أو ولد الابن أو اثنين فصاعدا من الأخوة والأخوات وهو للجدة عند عدم الأم ms16 ولبنت الابن مع بنت الصلب وهو للأخت من الأب مع الأخت من الأب والأم وهو فرض الأب مع الولد أو ولد الابن وفرض الجد عند عدم الأب وهو

فرض الواحد من ولد الأم, وتسقط الجدات بالأم والأجداد بالأب ويسقط ولد الأم مع أربعة الولد وولد الابن والأب والجد ويسقط الأخ للأب والأم مع ثلاثة الابن وابن الابن والأب ويسقط ولد الأب بهؤلاء الثلاثة وبالأخ للأب والأم وأربعة يعصبون أخوتهم الابن وابن الابن والأخ من الأب والأم والأخ من الأب وأربعة يرثون دون أخواتهم وهم الأعمام وبنو الأعمام وبنو الأخ وعصبات المولى المعتق.

"فصل" وتجوز الوصية بالمعلوم والمجهول والموجود والمعدوم وهي من الثلث فإن زاد وقف على إجازة الورثة ولا تجوز الوصية لوارث إلا أن يجيزها باقي الورثة وتصح الوصية من كل بالغ عاقل لكل متملك وفي سبيل الله تعالى وتصح الوصية إلى من اجتمعت فيه خمس خصال الإسلام والبلوغ والعقل والحرية والأمانة.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 107;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 108, 'كتاب النكاح وما يتعلق به من الأحكام والقضايا', 'كتاب النكاح وما يتعلق به من الأحكام والقضايا');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'النكاح مستحب لمن يحتاج إليه ويجوز للحر أن يجمع بين أربع حرائر وللعبد بين اثنين ولا ينكح الحر أمة إلا بشرطين عدم صداق الحرة وخوف العنت ونظر الرجل إلى المرأة على سبعة أضرب أحدها نظرة إلى أجنبية لغير حاجة فغير جائز والثاني نظرة إلى زوجته أو أمته فيجوز أن ينظر إلى ما عدا الفرج منهما والثالث نظرة إلى

ذوات محارمه أو أمته المزوجة فيجوز فيما عدا ما بين السرة والركبة والرابع النظر لأجل النكاح فيجوز إلى الوجه والكفين والخامس النظر للمداواة فيجوز إلى المواضع التي يحتاج إليها والسادس النظر للشهادة أو للمعاملة فيجوز إلى الوجه خاصة والسابع النظر إلى الأمة عند ابتياعها فيجوز إلى المواضع التي يحتاج إلى تقليبها.

"فصل" ولا يصح عقد النكاح إلا بولي وشاهدي عدل ويفتقر الولي والشاهدان إلى ستة شرائط: الإسلام والبلوغ والعقل والحرية والذكورة والعدالة إلا أنه لا يفتقر نكاح الذمية إلى إسلام الولي ولا نكاح الأمة إلى عدالة السيد وأولى الولاة الأب ثم الجد ms17 أبو الأب ثم الأخ للأب والأم ثم الأخ للأب ثم ابن الأخ للأب والأم ثم ابن الأخ للأب ثم العم ثم ابنه على هذا الترتيب فإذا عدمت العصبات فالمولى المعتق ثم عصباته ثم الحاكم ولا يجوز أن يصرح بخطبة معتدة ويجوز أن يعرض لها وينكحها بعد انقضاء عدتها والنساء على ضربين ثيبات وأبكار فالبكر يجوز للأب والجد إجبارها على النكاح والثيب لا يجوز تزويجها إلا بعد بلوغها وإذنها.

"فصل" والمحرمات بالنص أربع عشرة سبع بالنسب وهن الأم وإن علت والبنت وإن سفلت والأخت والخالة والعمة وبنت الأخ وبنت الأخت واثنتان بالرضاع الأم المرضعة والأخت من

الرضاع وأربع بالمصاهرة أم الزوجة والربيبة إذا دخل بالأم وزوجة الأب وزوجة الابن وواحدة من جهة الجمع وهي أخت الزوجة ولا يجمع بين المرأة وعمتها ولا بين المرأة وخالتها ويحرم من الرضاع ما يحرم من النسب وترد المرأة بخمسة عيوب بالجنون والجذام والبرص والرتق والقرن ويرد الرجل بخمسة عيوب بالجنون والجذام والبرص الجب والعنة.

"فصل" ويستحب تسمية المهر في النكاح فإن لم يسم صح العقد ووجب المهر بثلاثة أشياء أن يفرضه الزوج على نفسه أو يفرضه الحاكم أو يدخل بها فيجب مهر المثل وليس لأقل الصداق ولا لأكثره حد ويجوز أن يتزوجها على منفعة معلومة ويسقط بالطلاق قبل الدخول بها نصف المهر.

"فصل" والوليمة على العرس مستحبة والإجابة إليها واجبة إلا من عذر.

"فصل" والتسوية في القسم بين الزوجات واجبة ولا يدخل على غير المقسوم لها بغير حاجة وإذا أراد السفر أقرع بينهن وخرج بالتي تخرج لها القرعة وإذا تزوج جديدة خصها بسبع ليال إن كانت بكرا وبثلاث إن كانت ثيبا وإذا خاف نشوز المرأة وعظها فإن أبت إلا النشوز هجرها فإن أقامت عليه هجرها وضربها ويسقط بالنشوز قسمها ونفقتها.

"فصل" والخلع جائز على عوض معلوم وتملك به المرأة نفسها ولا رجعة له عليها إلا بنكاح جديد ويجوز الخلع في الطهر وفي الحيض ولا يلحق المختلعة الطلاق.

"فصل" والطلاق ضربان صريح وكناية فالصريح ثلاثة ألفاظ ms18 الطلاق والفراق والسراح ولا يفتقر صريح الطلاق إلى النية والكناية كل لفظ احتمل الطلاق وغيره ويفتقر إلى النية والنساء فيه ضربان ضرب في طلاقهن سنة وبدعة وهن ذوات الحيض فالسنة أن يوقع الطلاق في طهر غير مجامع فيه والبدعة أن يوقع الطلاق في الحيض أو في طهر جامعها فيه وضرب ليس في طلاقهن سنة ولا بدعة وهن أربع الصغيرة والآيسة والحامل والمختلعة التي لم يدخل بها.

"فصل" ويملك الحر ثلاث تطليقات والعبد تطليقتين ويصح الاستثناء في الطلاق إذا وصله به ويصح تعليقه بالصفة والشرط ولا يقع الطلاق قبل النكاح وأربع لا يقع طلاقهم الصبي والمجنون والنائم والمكره.

"فصل" وإذا طلق امرأته واحدة أو اثنتين فله مراجعتها ما لم تنقض عدتها فإن انقضت عدتها حل له نكاحها بعقد جديد وتكون معه على ما بقي من الطلاق فإن طلقها ثلاثا لم تحل له إلا بعد وجود خمس شرائط انقضاء عدتها منه وتزويجها بغيره ودخوله بها وإصابتها وبينونتها منه وانقضاء عدتها منه.

"فصل" وإذا حلف أن لا يطأ زوجته مطلقا أو مدة تزيد على أربعة أشهر فهو مول ويؤجل له إن سألت ذلك أربعة أشهر ثم يخير بين الفئة والتكفير أو الطلاق فإن امتنع طلق عليه الحاكم.

"فصل" والظهار أن يقول الرجل لزوجته أنت علي كظهر أمي فإذا قال ذلك ولم يتبعه بالطلاق صار عائدا ولزمته الكفارة والكفارة عتق رقبة مؤمنة سليمة من العيوب المضرة بالعمل والكسب فإن لم يجد فصيام شهرين متتابعين فإن لم يستطع فإطعام ستين مسكينا لكل مسكين مد ولا يحل للمظاهر وطؤها حتى يكفر.

"فصل" وإذا رمى الرجل زوجته بالزنا فعليه حد القذف إلا أن يقيم البينة أو يلاعن فيقول عند الحاكم في الجامع على المنبر في جماعة من الناس أشهد بالله إنني لمن الصادقين فيما رميت به زوجتي فلانة من الزنا وإن هذا الولد من الزنا وليس مني أربع مرات ويقول في المرة الخامسة بعد أن يعظه الحاكم وعلي لعنة الله إن كنت من الكاذبين ويتعلق بلعانة خمسة ms19 أحكام سقوط الحد عنه ووجوب الحد عليها وزوال الفراش ونفي الولد والتحريم على الأبد ويسقط الحد عليها بأن تلتعن فتقول أشهد بالله إن فلانا هذا لمن الكاذبين فيما رماني به من الزنا أربع مرات وتقول في الخامسة بعد أن يعظها الحاكم وعلى غضب الله إن كان من الصادقين.

"فصل" والمعتدة على ضربين متوفى عنها وغير متوفى عنها فالمتوفى عنها إن كانت حاملا فعدتها بوضع الحمل وإن كانت حائلا فعدتها أربعة أشهر وعشر وغير المتوفى عنها إن كانت حاملا فعدتها بوضع الحمل وإن كانت حائلا وهي من ذوات الحيض فعدتها ثلاثة قروء وهي الأطهار وإن كانت صغيرة أو آيسة فعدتها ثلاثة أشهر والمطلقة قبل الدخول بها لا عدة عليها وعدة الأمة بالحمل كعدة الحرة وبالإقراء أن تعتد بقرأين وبالشهور عن الوفاة أن تعتد بشهرين وخمس ليال وعن الطلاق أن تعتد بشهر ونصف فإن اعتدت بشهرين كان أولى.

"فصل" ويجب للمعتدة الرجعية السكني والنفقة ويجب للبائن السكني دون النفقة إلا أن تكون حاملا ويجب على المتوفى عنها زوجها الإحداد وهو الامتناع من الزينة والطيب وعلى المتوفى عنها زوجها والمبتوتة ملازمة البيت إلا لحاجة.

"فصل" ومن استحدث ملك أمة حرم عليه الاستمتاع بها حتى يستبرئها إن كانت من ذوات الحيض بحيضة وإن كانت من ذوات الشهور بشهرفقط وإن كانت من ذوات الحمل بالوضع وإذا مات سيد أم الولد استبرأت نفسها كالأمة.

"فصل" وإذا أرضعت المرأة بلبنها ولدا صار الرضيع ولدها بشرطين أحدهما أن يكون له دون الحولين والثاني أن ترضعه خمس

رضعات متفرقات ويصير زوجها أبا له ويحرم على المرضع التزويج إليها وإلى كل من ناسبها ويحرم عليها التزويج إلى المرضع وولده دون من كان في درجته أو أعلى طبقة منه.

"فصل" ونفقة العمودين من الأهل واجبة للوالدين والمولودين فأما الوالدون: فتجب نفقتهم بشرطين الفقر والزمانة أو الفقر والجنون وأما المولودون فتجب نفقتهم بثلاث شرائط الفقر والصغر أو الفقر والزمانة أو الفقر والجنون ونفقة الرقيق والبهائم واجبة ولا يكلفون من العمل ما لا ms20 يطيقون ونفقة الزوجة الممكنة من نفسها واجبة وهي مقدرة فإن كان الزوج موسرا فمدان من غالب قوتها ومن الأدم والكسوة ما جرت به العادة وإن كان معسرا فمد من غاب قوت البلد وما يأتدم به المعسرون ويكسونه وإن كان متوسطا فمد ونصف ومن الأدم والكسوة الوسط وإن كانت ممن يخدم مثلها فعليه إخدامها وإن أعسر بنفقتها فلها فسح النكاح وكذلك أن أعسر بالصداق قبل الدخول.

"فصل" وإذا فارق الرجل زوجته وله منها ولد فهي أحق بحضانته إلى سبع سنين ثم يخير بين أبويه فأيهما اختار سلم إليه, وشرائط الحضانة سبع العقل والحرية والدين والعفة والأمانة والإقامة والخلو من زوج فإن اختل منها شرط سقطت.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 108;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 109, 'كتاب الجنايات', 'كتاب الجنايات');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'القتل على ثلاثة أضرب عمد محض وخطأ محض وعمد خطأ فالعمد المحض أن يعمد إلى ضربه بما يقتل غالبا ويقصد قتله بذلك فيجب القود عليه فإن عفا عنه وجبت دية مغلظة حالة في مال القاتل والخطأ المحض أن يرمي إلى شيء فيصيب رجلا فيقتله فلا قود عليه بل تجب عليه دية مخففة على العاقلة مؤجلة في ثلاث سنين

وعمد الخطأ أن يقصد ضربه بما لا يقتل غالبا فيموت فلا قود عليه بل تجب دية مغلظة على العاقلة مؤجلة في ثلاث سنين وشرائط وجوب القصاص أربعة أن يكون القاتل بالغا عاقلا وأن لا يكون والدا للمقتول وأن لا يكون المقتول أنقص من القاتل بكفر أو رق وتقتل الجماعة بالواحد وكل شخصين جرى القصاص بينهما في النفس يجري بينهما في الأطراف وشرائط وجوب القصاص في الأطراف بعد الشرائط المذكورة اثنان الاشتراك في الاسم الخاص, اليمنى باليمنى, واليسرى باليسرى, وأن لا يكون بأحد الطرفين شلل, وكل عضو أخذ من مفصل ففيه القصاص ولا قصاص في الجروح إلا في الموضحة.

"فصل" والدية على ضربين مغلظة ومخففة فالمغلظة مائة من الإبل ثلاثون حقة وثلاثون جذعة وأربعون خلفة في بطونها أولادها والمخففة مائة من الإبل عشرون حقة وعشرون جذعة, وعشرون بنت

لبون, وعشرون ابن لبون, وعشرون بنت مخاض, فإن عدمت ms21 الإبل انتقل إلى قيمتها وقيل ينتقل إلى ألف دينار أو اثني عشر ألف درهم, وإن غلظت زيد عليها الثلث وتغلظ دية الخطأ في ثلاثة مواضع إذا قتل في الحرم, أو في الأشهر الحرم, أو قتل ذا رحم محرم, ودية المرأة على النصف من دية الرجل ودية اليهودي والنصراني ثلث دية المسلم وأما المجوسي ففيه ثلثا عشر دية المسلم وتكمل دية النفس في قطع اليدين والرجلين والأنف والأذنين والعينين والجفون الأربعة واللسان والشفتين وذهاب الكلام وذهاب البصر وذهاب السمع وذهاب الشم وذهاب العقل والذكر والأنثيين وفي الموضحة والسن خمس من الإبل وفي كل عضو لا منفعة فيه حكومة ودية العبد قيمته ودية الجنين الحر غرة عبد أو أمة ودية الجنين الرقيق عشر قيمة أمه.

"فصل" وإذا اقترن بدعوى الدم لوث يقع به في النفس صدق المدعي حلف المدعي خمسين يمينا واستحق الدية وإن لم يكن هناك لوث فاليمين على المدعى عليه وعلى قاتل النفس المحرمة كفارة عتق رقبة مؤمنة سليمة من العيوب المضرة فإن لم يجد فصيام شهرين متتابعين.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 109;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 110, 'كتاب الحدود', 'كتاب الحدود');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'والزاني على ضربين محصن وغير محصن فالمحصن حده الرجم, وغير

المحصن حده مائة جلدة, وتغريب عام, إلى مسافة القصر وشرائط الإحصان أربع البلوغ والعقل والحرية ووجود الوطء في نكاح صحيح والعبد والأمة حدهما نصف حد الحر وحكم اللواط وإتيان البهائم كحكم الزنا, ومن وطئ فيما دون الفرج عزر ولا يبلغ بالتعزير أدنى الحدود.

"فصل" وإذا قذف غيره بالزنا فعليه حد القذف بثمانية شرائط, ثلاثة منها في القاذف, وهو أن يكون بالغا عاقلا, وأن لا يكون والدا للمقذوف, وخمسة في المقذوف, وهو أن يكون مسلما بالغا عاقلا حرا عفيفا ويحد الحر ثمانين والعبد أربعين ويسقط حد القذف بثلاثة أشياء إقامة البينة أو عفو المقذوف أو اللعان في حق الزوجة.

"فصل" ومن شرب خمرا أو شرابا مسكرا يحد أربعين ويجوز أن يبلغ به ثمانين على وجه التعزير,

ويجب عليه بأحد أمرين بالبينة أو الإقرار ولا يحد بالقيء والاستنكاه.

"فصل" وتقطع يد السارق ms22 بثلاثة شرائط أن يكون بالغا عاقلا وأن يسرق نصابا قيمته ربع دينار من حرز مثله لا ملك له فيه ولا شبهة في مال المسروق منه وتقطع يده اليمنى من مفصل الكوع فإن سرق ثانيا قطعت رجله اليسرى فإن سرق ثالثا قطعت يده اليسرى فإن سرق رابعا قطعت رجله اليمنى فإن سرق بعد ذلك عزر وقيل يقتل صبرا

"فصل" وقطاع الطريق على أربعة أقسام إن قتلوا ولم يأخذوا

المال قتلوا فإن قتلوا وأخذوا المال قتلوا وصلبوا وإن أخذوا المال ولم يقتلوا قطعت أيديهم وأرجلهم من خلاف فإن أخافوا السبيل ولم يأخذوا مالا ولم يقتلوا حبسوا وعزروا ومن تاب منهم قبل القدرة عليه سقطت عنه الحدود وأخذ بالحقوق.

"فصل" ومن قصد بأذى في نفسه أو ماله أو حريمه فقاتل عن ذلك وقتل فلا ضمان عليه وعلى راكب الدابة ضمان ما أتلفته دابته.

"فصل" ويقاتل أهل البغي بثلاثة شرائط: أن يكونوا في منعة, وأن يخرجوا عن قبضة الإمام, وأن يكون لهم تأويل سائغ ولا يقتل أسيرهم ولا يغنم مالهم ولا يذفف على جريحهم.

"فصل" ومن ارتد عن الإسلام استتيب ثلاثا فإن تاب وإلا قتل ولم يغسل ولم يصل عليه ولم يدفن في مقابر المسلمين.

"فصل" وتارك الصلاة على ضربين: أحدهما أن يتركها غير معتقد لوجوبها فحكمه حكم المرتد والثاني أن يتركها كسلا معتقدا لوجوبها فيستتاب فإن تاب وصلى وإلا قتل حدا وكان حكمه حكم المسلمين.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 110;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 111, 'كتاب الجهاد', 'كتاب الجهاد');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وشرائط وجوب الجهاد سبع خصال: الإسلام والبلوغ والعقل والحرية والذكورة والصحة والطاقة على القتال ومن أسر من الكفار

فعلى ضربين: ضرب يصير رقيقا بنفس السبي وهم الصبيان والنساء, وضرب لا يرق بنفس السبي وهم الرجال البالغون والإمام مخير فيهم بين أربعة أشياء القتل والاسترقاق والمن والفدية بالمال أو بالرجال يفعل من ذلك ما فيه المصلحة ومن أسلم قبل الأسر أحرز ماله ودمه وصغار أولاده ويحكم للصبي بالإسلام عند وجود ثلاثة أسباب أن يسلم أحد أبويه أو يسبيه مسلم منفردا عن أبويه أو يوجد لقيطا في دار ms23 الإسلام.

"فصل" ومن قتل قتيلا أعطى سلبه وتقسم الغنيمة بعد ذلك على خمسة أخماس فيعطى أربعة أخماسها لمن شهد الوقعة للفارس ثلاثة أسهم وللراجل سهم ولا يسهم إلا لمن استكملت فيه خمس شرائط: الإسلام والبلوغ والعقل والحرية والذكورة فإن اختل شرط من ذلك رضخ له ولم يسهم له ويقسم له الخمس على خمسة أسهم, سهم لرسول الله صلى الله عليه وسلم يصرف بعده للمصالح وسهم لذوي القربى وهم بنو هاشم وبنو المطلب وسهم لليتامى وسهم للمساكين وسهم لأبناء السبيل.

"فصل" ويقسم مال الفيء على خمس فرق: يصرف خمسة على من يصرف عليهم خمس الغنيمة ويعطى أربعة أخماسه للمقاتلة وفي مصالح المسلمين.

"فصل" وشرائط وجوب الجزية خمس خصال البلوغ والعقل والحرية والذكورة وأن يكون من أهل الكتاب أو ممن له شبهة

كتاب وأقل الجزية دينار في كل حول ويؤخذ من المتوسط ديناران ومن الموسر أربعة دنانير ويجوز أن يشترط عليهم الضيافة فضلا عن مقدار الجزية ويتضمن عقد الجزية أربعة أشياء أن يؤدوا الجزية عن وأن تجري عليهم أحكام الإسلام وأن لا يذكروا دين الإسلام إلا بخير وأن لا يفعلوا ما فيه ضرر على المسلمين ويعرفون بلبس الغيار وشد الزنار ويمنعون من ركوب الخيل.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 111;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 112, 'كتاب الصيد والذبائح', 'كتاب الصيد والذبائح');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وما قدر على ذكاته فذكاته في حلقه ولبته وما لم يقدر على ذكاته فذكاته عقره حيث قدر عليه وكمال الذكاة أربعة أشياء قطع الحلقوم والمريء والودجين والمجزئ منها شيئان قطع الحلقوم والمريء ويجوز الاصطياد بكل جارحة معلمة من السباع ومن جوارح الطير وشرائط تعليمها أربعة أن تكون إذا أرسلت استرسلت وإذا زجرت انزجرت وإذا قتلت صيدا لم تأكل منه شيئا وأن يتكرر ذلك منها فإن عدمت أحد الشرائط لم يحل ما أخذته إلا أن يدرك حيا فيذكى وتجوز الذكاة بكل ما يجرح إلا بالسن والظفر وتحل ذكاة كل مسلم وكتابي ولا تحل ذبيحة مجوسي ولا وثني وذكاة الجنين بذكاة أمه إلا أن يوجد حيا فيذكى وما قطع من حي فهو ميت

إلا الشعور المنتفع بها ms24 في المفارش والملابس.

"فصل" وكل حيوان استطابته العرب فهو حلال إلا ما ورد الشرع بتحريمه وكل حيوان استخبثته العرب فهو حرام إلا ما ورد الشرع بإباحته ويحرم من السباع ما له ناب قوي يعدو به ويحرم من الطيور ما له مخلب قوي يجرح به ويحل للمضطر في المخمصة أن يأكل من الميتة المحرمة ما يسد به رمقه وميتتان حلالان السمك والجراد ودمان حلالان الكبد والطحال.

"فصل" والأضحية سنة مؤكدة ويجزئ فيها الجذع من الضأن والثني من المعز والثني من الإبل والثني من البقر وتجزئ البدنة عن سبعة والبقرة عن سبعة والشاة عن واحد وأربع لا تجزئ في الضحايا العوراء البين عورها والعرجاء البين عرجها والمريضة البين مرضها والعجفاء التي ذهب مخها من الهزال ويجزئ الخصي والمكسور القرن ولا تجزئ المقطوعة الأذن والذنب ووقت الذبح من وقت صلاة العيد إلى غروب الشمس من آخر أيام التشريق ويستحب عند الذبح خمسة أشياء: التسمية والصلاة على النبي صلى الله عليه وسلم واستقبال القبلة والتكبير والدعاء بالقبول ولا يأكل المضحي شيئا من الأضحية المنذورة ويأكل من المتطوع بها ولا يبيع من الأضحية ويطعم الفقراء والمساكين.

"فصل" والعقيقة مستحبة وهي الذبيحة عن المولود يوم سابعه ويذبح عن الغلام شاتان وعن الجارية شاة ويطعم الفقراء والمساكين.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 112;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 113, 'كتاب السبق والرمي', 'كتاب السبق والرمي');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'وتصح المسابقة على الدواب والمناضلة بالسهام إذا كانت المسافة معلومة وصفة المناضلة معلومة

ويخرج العوض أحد المتسابقين حتى إنه إذا سبق استرده وإن سبق أخذه صاحبه له وإن أخرجاه معا لم يجز إلا أن يدخلا بينهما محللا إن سبق أخذ العوض وإن سبق لم يغرم.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 113;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 114, 'كتاب الأيمان والنذور', 'كتاب الأيمان والنذور');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ولا ينعقد اليمين إلا بالله تعالى أو باسم من أسمائه أو صفة من صفات ذاته ومن حلف بصدقة ماله فهو مخير بين الصدقة أو كفارة اليمين ولا شيء في لغو اليمين ومن حلف أن لا يفعل شيئا فأمر غيره بفعله لم يحنث ومن حلف على فعل أمرين ففعل أحدهما لم يحنث وكفارة اليمين هو مخير فيها بين ثلاثة أشياء: ms25 عتق رقبة مؤمنة أو إطعام عشرة مساكين كل مسكين مدا أو كسوتهم ثوبا ثوبا فإن لم يجد فصيام ثلاثة أيام.

"فصل" والنذر يلزم في المجازاة على مباح وطاعة كقوله إن شفى الله مريضي فلله علي أن أصلي أو أصوم أو أتصدق ويلزمه من ذلك ما يقع عليه الاسم ولا نذر في معصية كقوله إن قتلت فلانا فلله علي كذا ولا يلزم النذر على ترك مباح كقوله لا آكل لحما ولا أشرب لبنا وما أشبه ذلك.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 114;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 115, 'كتاب الأقضية والشهادات', 'كتاب الأقضية والشهادات');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ولا يجوز أن يلي القضاء إلا من استكملت فيه خمس عشرة خصلة الإسلام والبلوغ والعقل والحرية والذكورية والعدالة ومعرفة أحكام الكتاب والسنة ومعرفة الإجماع ومعرفة الاختلاف ومعرفة طرق الاجتهاد ومعرفة طرف من لسان العرب ومعرفة تفسير كتاب الله تعالى وأن يكون سميعا وأن يكون بصيرا وأن يكون كاتبا وأن يكون مستيقظا ويستحب أن يجلس في وسط البلد في موضع بارز للناس ولا حاجب له ولا يقعد للقضاء في المسجد ويسوي بين الخصمين في ثلاثة أشياء في المجلس واللفظ واللحظ ولا يجوز أن يقبل الهدية من أهل عمله ويجتنب القضاء في عشرة مواضع عند الغضب والجوع والعطش وشدة الشهوة والحزن والفرح المفرطين وعند المرض ومدافعة الأخبثين وعند النعاس وشدة الحر والبرد ولا يسأل المدعي عليه إلا بعد كمال الدعوى ولا يحلفه إلا بعد سؤال المدعي ولا يلقن خصما حجته ولا يفهمه كلاما ولا يتعنت بالشهداء ولا يقبل الشهادة إلا ممن ثبتت عدالته ولا يقبل شهادة عدو على عدوه ولا شهادة والد لولده ولا ولد لوالده ولا يقبل كتاب قاض

إلى قاض آخر في الأحكام إلا بعد شهادة شاهدين يشهدان بما فيه.

"فصل" ويفتقر القاسم إلى سبعة شرائط: الإسلام والبلوغ والعقل والحرية والذكورة والعدالة والحساب فإن تراضى الشريكان بمن يقسم بينهما لم يفتقر إلى ذلك وإذا كان في القسمة تقويم لم يقتصر فيه على أقل من اثنين وإذا دعا أحد الشريكين شريكه إلى قسمة ما لا ضرر فيه لزم الآخر إجابته.

"فصل" وإذا كان ms26 مع المدعي بينة سمعها الحاكم وحكم له بها وإن لم تكن له بينة فالقول قول المدعي عليه بيمينه فإن نكل عن اليمين ردت على المدعي فيحلف ويستحق وإذا تداعيا شيئا في يد أحدهما فالقول قول صاحب اليد بيمينه وإن كان في أيديهما تحالفا وجعل بينهما ومن حلف على فعل نفسه حلف على البت والقطع ومن حلف على فعل غيره فإن كان إثباتا حلف على البت والقطع وإن كان نفيا حلف على نفى العلم.

"فصل" ولا تقبل الشهادة إلا ممن اجتمعت فيه خمس خصال: الإسلام والبلوغ والعقل والحرية والعدالة

وللعدالة خمس شرائط أن يكون مجتنبا للكبائر غير مصر على القليل من الصغائر سليم السريرة مأمون الغضب محافظا على مروءة مثله.

"فصل" والحقوق ضربان حقوق الله تعالى وحقوق الآدميين فأما حقوق

الآدميين فهي على ثلاثة أضرب ضرب لا يقبل فيه إلا شاهدان ذكران وهو ما لا يقصد منه المال ويطلع عليه الرجال وضرب يقبل فيه شاهدان أو رجل وامرأتان أو شاهد ويمين المدعي وهو ما كان القصد منه المال وضرب يقبل فيه رجل وامرأتان أو أربع نسوة وهو ما لا يطلع عليه الرجال وأما حقوق الله تعالى فلا تقبل فيها النساء وهي على ثلاثة أضرب ضرب لا يقبل فيه أقل من أربعة وهو الزنا وضرب يقبل فيه اثنان وهو ما سوى الزنا من الحدود وضرب يقبل فيه واحد وهو هلال رمضان ولا تقبل شهادة الأعمى إلا في خمسة مواضع: الموت والنسب والملك المطلق والترجمة وما شهد به قبل العمى وما شهد به على المضبوط ولا تقبل شهادة جار لنفسه نفعا ولا دافع عنها ضررا.', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 115;
INSERT OR IGNORE INTO pesantren_bab (kitab_slug, bab_order, name_id, name_ar) VALUES ('taqrib', 116, 'كتاب العتق', 'كتاب العتق');
INSERT OR IGNORE INTO pesantren_matn (bab_id, matn_order, title_id, title_ar, text_ar, translation_id, explanation_id, quran_refs_json, hadits_refs_json) SELECT id, 1, NULL, NULL, 'ويصح العتق من كل مالك جائز التصرف في ملكه ويقع بصريح العتق والكتابة مع النية وإذا أعتق بعض عبد عتق جميعه وإن أعتق شركا له في عبد وهو موسر سرى العتق إلى باقية وكان عليه قيمة نصيب شريكه ومن ملك واحدا من والديه أو مولودية عتق عليه.

"فصل" والولاء من حقوق العتق وحكمه حكم التعصيب عند ms27 عدمه وينتقل الولاء عن المعتق إلى الذكور من عصبته وترتيب

العصبات في الولاء كترتيبهم في الإرث ولا يجوز بيع الولاء ولا هبته.

"فصل" ومن قال لعبده: إذا مت فأنت حر فهو مدبر يعتق بعد وفاته من ثلثه ويجوز له أن يبيعه في حال حياته ويبطل تدبيره وحكم المدبر في حال حياة السيد كحكم العبد القن.

"فصل" والكتابة مستحبة إذا سألها العبد وكان مأمونا مكتسبا ولا تصح إلا بمال معلوم ويكون مؤجلا إلى أجل معلوم أقله نجمان وهي من جهة السيد لازمة ومن جهة المكاتب جائزة فله فسحها متى شاء وللمكاتب التصرف فيما في يده من المال وعلى السيد أن يضع عنه من مال الكتابة ما يستعين به على أداء نجوم الكتابة ولا يعتق إلا بأداء جميع المال.

"فصل" وإذا أصاب السيد أمته فوضعت ما تبين فيه شيء من خلق آدمي حرم عليه بيعها ورهنها وهبتها وجاز له التصرف فيها بالاستخدام والوطء وإذا مات السيد عتقت من رأس ماله قبل الديون والوصايا وولدها من غيره بمنزلتها ومن أصاب أمة غيره بنكاح فالولد منها مملوك لسيدها وإن أصابها بشبهة فولده منها حر وعليه قيمته للسيد وإن ملك الأمة المطلقة بعد ذلك لم تصر أم ولد له بالوطء في النكاح وصارت أم ولد له بالوطء بالشبهة على أحد القولين والله أعلم.

تم الكتاب  ms28', NULL, NULL, NULL, NULL FROM pesantren_bab WHERE kitab_slug = 'taqrib' AND bab_order = 116;
